mapper.select:
SELECT c.change_id, m.name, c.change_type, c.change_date, c.prev_status, c.new_status, c.reason, c.reg_date AS registered_at FROM erp_member_change c LEFT JOIN erp_member m ON c.member_id = m.member_id
AND m.name LIKE '%' || #{keyword} || '%'
ORDER BY c.reg_date DESC LIMIT #{limit} OFFSET #{offset}
